function getRecentFoods(limit=8){const seen=new Set(),items=[];const dates=Object.keys(dailyLog).sort().reverse();for(const date of dates){const list=dailyLog[date]?.entries||[];for(let i=list.length-1;i>=0;i--){const e=list[i];const key=String(e.label||'').toLowerCase().trim()+'|'+fmt(safeNum(e.macros?.calories));if(!e.label||seen.has(key))continue;seen.add(key);items.push(e);if(items.length>=limit)return items}}return items}
