function safeNum(v){const n=Number(v||0);return Number.isFinite(n)?n:0}
function isUUID(v){return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(String(v||''))}
function normalTime(v){if(!v)return'';const t=new Date(v);return Number.isNaN(t.getTime())?String(v).slice(0,19):t.toISOString().slice(0,19)}
function detailSignature(details){return (details||[]).map(d=>`${String(d.name||'').toLowerCase().trim()}:${fmt(safeNum(d.amount))}:${String(d.unit||'').toLowerCase().trim()}`).sort().join(',')}
function entrySignature(e){const m=e.macros||{};return [String(e.label||'').toLowerCase().trim(),normalTime(e.createdAt),fmt(safeNum(m.calories)),fmt(safeNum(m.protein)),fmt(safeNum(m.carbs)),fmt(safeNum(m.fat)),fmt(safeNum(m.fibre)),fmt(safeNum(m.addedSugar)),fmt(safeNum(m.naturalSugar)),detailSignature(e.details)].join('|')}
function mergeLogs(base,incoming){const out=JSON.parse(JSON.stringify(base||{}));for(const[date,data]of Object.entries(incoming||{})){if(!out[date])out[date]={entries:[]};if(!Array.isArray(out[date].entries))out[date].entries=[];for(const entry of(data.entries||[])){const entries=out[date].entries;const idIndex=entries.findIndex(e=>e.id===entry.id);if(idIndex>=0){entries[idIndex]={...entries[idIndex],...entry};continue}const sig=entrySignature(entry);const sigIndex=entries.findIndex(e=>entrySignature(e)===sig);if(sigIndex>=0){if(isUUID(entry.id)&&!isUUID(entries[sigIndex].id))entries[sigIndex]=entry;continue}entries.push(entry)}}return out}

function todayLocal(){const d=new Date();return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`}
function shiftDate(s,o){const[y,m,d]=s.split('-').map(Number);const date=new Date(y,m-1,d);date.setDate(date.getDate()+o);return `${date.getFullYear()}-${String(date.getMonth()+1).padStart(2,'0')}-${String(date.getDate()).padStart(2,'0')}`}
function shortDateLabel(s){const[y,m,d]=s.split('-').map(Number);return new Date(y,m-1,d).toLocaleDateString('en-GB',{weekday:'short',day:'numeric'})}
function longDateLabel(s){const[y,m,d]=s.split('-').map(Number);return new Date(y,m-1,d).toLocaleDateString('en-GB',{weekday:'short',day:'numeric',month:'short',year:'numeric'})}

