function addMacros(a,b){for(const k of Object.keys(a))a[k]+=safeNum(b[k]);a.totalSugar=a.addedSugar+a.naturalSugar;return a}
function ingredientUnitLabel(i){return i&&['item','scoop','can','pack'].includes(i.unit)?i.unit:'g'}
