function sugarText(m){return`Added sugar: ${fmt(m.addedSugar)}g · Natural sugar: ${fmt(m.naturalSugar)}g · Total sugar: ${fmt(m.totalSugar)}g`}
function foodWordKey(w){const s=String(w||'').toLowerCase();if(s.length>4&&s.endsWith('ies'))return s.slice(0,-3)+'y';if(s.length>3&&s.endsWith('es'))return s.slice(0,-2);if(s.length>3&&s.endsWith('s'))return s.slice(0,-1);return s}
function foodPhraseKey(v){return String(v||'').toLowerCase().replace(/&/g,' and ').replace(/[^a-z0-9%]+/g,' ').trim().split(/\s+/).filter(Boolean).map(foodWordKey).join(' ')}
function ingredientMatchScore(i,v){const q=foodPhraseKey(v),name=foodPhraseKey(i.name),id=foodPhraseKey(i.id);if(!q)return 0;if(name===q||id===q)return 100;if(name.startsWith(q+' ')||id.startsWith(q+' '))return 84;if(name.endsWith(' '+q)||id.endsWith(' '+q))return 78;if(name.includes(' '+q+' ')||id.includes(' '+q+' '))return 72;const words=q.split(' ');if(words.every(w=>name.split(' ').includes(w)||id.split(' ').includes(w)))return 58-words.length;return 0}
function findIngredientByInput(v){const q=String(v||'').trim();if(!q)return null;const scored=ingredients.map(i=>({ingredient:i,score:ingredientMatchScore(i,q)})).filter(x=>x.score>0).sort((a,b)=>b.score-a.score||a.ingredient.name.localeCompare(b.ingredient.name));return scored[0]?.ingredient||null}
function findIngredientMatches(v,limit=8){const q=String(v||'').trim();if(!q)return[];return ingredients.map(i=>({ingredient:i,score:ingredientMatchScore(i,q)})).filter(x=>x.score>0).sort((a,b)=>b.score-a.score||a.ingredient.name.localeCompare(b.ingredient.name)).slice(0,limit).map(x=>x.ingredient)}
function syncCustomIngredientStore(ing){const custom=loadJSON(customIngredientsKey,[]);const next=custom.filter(i=>i.id!==ing.id&&i.name.toLowerCase()!==ing.name.toLowerCase());next.push(ing);saveJSON(customIngredientsKey,next)}
function upsertIngredient(ing){const existing=ingredientMap.get(ing.id)||ingredients.find(i=>i.name.toLowerCase()===ing.name.toLowerCase());if(existing)return existing;ingredients.push(ing);ingredientMap.set(ing.id,ing);syncCustomIngredientStore(ing);populateIngredientDatalist();populateIngredientSelect();refreshAllRecipes();refreshTagFilter();renderRecipes();return ing}
function ingredientFromCandidate(c){if(c.ingredient)return c.ingredient;const m=c.macros||emptyMacros();return{id:c.id||`custom-${slugify(c.name)}-${Date.now()}`,name:c.name,unit:c.unit||'100g',calories:safeNum(m.calories),protein:safeNum(m.protein),carbs:safeNum(m.carbs),fat:safeNum(m.fat),fibre:safeNum(m.fibre),addedSugar:safeNum(m.addedSugar),naturalSugar:safeNum(m.naturalSugar),source:c.source||'custom',sourceId:c.sourceId||''}}
function candidateFromIngredient(i,source='Saved'){return{id:i.id,name:i.name,unit:i.unit,source,ingredient:i,macros:{calories:safeNum(i.calories),protein:safeNum(i.protein),carbs:safeNum(i.carbs),fat:safeNum(i.fat),fibre:safeNum(i.fibre),addedSugar:safeNum(i.addedSugar),naturalSugar:safeNum(i.naturalSugar)}}}
function lookupAmount(){return Number(document.getElementById('foodLookupAmount')?.value||0)}
function lookupInputValue(){return document.getElementById('foodLookupInput')?.value.trim()||''}
function setLookupStatus(message=''){const el=document.getElementById('foodLookupStatus');if(el)el.textContent=message}
function clearFoodLookup(clearInput=true){resetFoodVoiceSession();const input=document.getElementById('foodLookupInput');if(clearInput&&input)input.value='';updateFoodLookupUnit();renderFoodLookupCandidates([]);setLookupStatus('')}
function findIngredientForMealName(v){const q=String(v||'').trim();if(!q)return null;return findIngredientByInput(q)||(/s$/i.test(q)?findIngredientByInput(q.replace(/s$/i,'')):null)}
function normalizeMealFoodName(v){return String(v||'').replace(/\b(?:for breakfast|for lunch|for dinner|for snack|for a snack)\b/ig,' ').replace(/^(?:please\s+)?(?:log|add)\s+/i,'').replace(/^(?:i\s+)?(?:had|ate|drank|logged)\s+/i,'').replace(/^(?:a|an|the|some|my)\s+/i,'').replace(/\s+/g,' ').trim()}
function mealQuantityValue(v){const words={a:1,an:1,one:1,two:2,three:3,four:4,five:5,six:6,seven:7,eight:8,nine:9,ten:10,half:.5};const raw=String(v||'').toLowerCase();if(Object.prototype.hasOwnProperty.call(words,raw))return words[raw];const n=Number(raw);return Number.isFinite(n)?n:null}
function normalizeMealUnit(v){const raw=String(v||'').toLowerCase();if(!raw)return'';if(raw.startsWith('kg'))return'kg';if(raw==='g'||raw.startsWith('gram'))return'g';if(raw==='ml'||raw.startsWith('millilitre'))return'ml';if(raw.startsWith('item'))return'item';if(raw.startsWith('serving')||raw.startsWith('portion'))return'serving';if(raw.startsWith('pack'))return'pack';if(raw.startsWith('can'))return'can';if(raw.startsWith('scoop'))return'scoop';return''}
function normalizeVoiceFoodText(text){return String(text||'').replace(/\bgrammes?\b/gi,'grams').replace(/\bgrams?\b/gi,'g').replace(/\bkilograms?\b/gi,'kg').replace(/\bmillilit(?:re|er)s?\b/gi,'ml').replace(/\bblue\s+berr(?:y|ies)\b/gi,'blueberries').replace(/\bchia\s+seed\b/gi,'chia seeds').replace(/\byoghurt\b/gi,'yogurt').replace(/\bzero\s*percent\b/gi,'0%').replace(/\s+/g,' ').trim()}
function mealBreaksForSpeech(text){const amount='\\d+(?:\\.\\d+)?|half|one|two|three|four|five|six|seven|eight|nine|ten|a|an',unit='g|kg|ml|item|items|serving|servings|portion|portions|pack|packs|can|cans|scoop|scoops';return normalizeVoiceFoodText(text).replace(/[;\n]+/g,',').replace(/\s+(?:plus|with|alongside|and|or)\s+/gi,',').replace(new RegExp(`(\\S)\\s+(?=(?:about\\s+|around\\s+|roughly\\s+)?(?:${amount})\\s*(?:${unit})\\b)`,'gi'),'$1, ')}
function parseMealPart(rawPart){let part=normalizeMealFoodName(rawPart);if(!part)return null;const unitPattern='g|gram|grams|kg|kilogram|kilograms|ml|millilitre|millilitres|item|items|serving|servings|portion|portions|pack|packs|can|cans|scoop|scoops';let amount=null,unit='';let m=new RegExp(`^(?:about\\s+|around\\s+|roughly\\s+)?(\\d+(?:\\.\\d+)?|half|one|two|three|four|five|six|seven|eight|nine|ten|a|an)\\s*(${unitPattern})?\\s+(.+)$`,'i').exec(part);if(m){amount=mealQuantityValue(m[1]);unit=normalizeMealUnit(m[2]);part=m[3]}else{m=new RegExp(`^(.+?)\\s+(\\d+(?:\\.\\d+)?)\\s*(${unitPattern})$`,'i').exec(part);if(m){part=m[1];amount=mealQuantityValue(m[2]);unit=normalizeMealUnit(m[3])}}part=normalizeMealFoodName(part.replace(/\bof\b\s+/i,''));return part?{raw:String(rawPart||'').trim(),name:part,amount,unit}:null}
function parseMealItems(text){const raw=mealBreaksForSpeech(text);if(!raw)return[];const parts=raw.split(',').map(parseMealPart).filter(Boolean);return parts.length?parts:[parseMealPart(raw)].filter(Boolean)}
function defaultAmountForCandidate(c){const unit=c?.unit||c?.ingredient?.unit||'100g';return ['item','scoop','can','pack'].includes(unit)?1:(Number(c?.defaultAmount||0)||100)}
function parsedAmountForCandidate(c,item,forceDefault=false){if(item&&safeNum(item.amount)>0){if(item.unit==='kg')return item.amount*1000;if(item.unit==='g'||item.unit==='ml')return item.amount;const unit=c?.unit||c?.ingredient?.unit||'100g';if(['item','scoop','can','pack'].includes(unit))return item.amount;return item.amount*(Number(c?.defaultAmount||0)||100)}return forceDefault?defaultAmountForCandidate(c):Number(c?.defaultAmount||0)}
function withParsedMealAmount(candidate,item,mealReview=false){const amount=parsedAmountForCandidate(candidate,item,mealReview);const noteParts=[];if(candidate.note)noteParts.push(candidate.note);if(mealReview&&item?.raw)noteParts.push(`From "${item.raw}". Review before adding.`);return{...candidate,defaultAmount:amount||candidate.defaultAmount,mealReview,mealItem:item?.raw||'',note:noteParts.join(' ')}}
