function updateFoodLookupUnit(){const item=singleMealItemForLookup();const ing=findIngredientForMealName(item?.name||lookupInputValue());const unit=document.getElementById('foodLookupUnit');const amount=document.getElementById('foodLookupAmount');if(!unit||!amount)return;unit.textContent=ing?ingredientUnitLabel(ing):'g';if(ing&&['item','scoop','can','pack'].includes(ing.unit)&&Number(amount.value)===100)amount.value=1}
function renderFoodLookupCandidates(candidates,query=lookupInputValue()){foodLookupCandidates=candidates;foodLookupResultsQuery=query;const box=document.getElementById('foodLookupResults');if(!box)return;box.dataset.query=query;if(!candidates.length){box.innerHTML='';box.removeAttribute('data-query');foodLookupResultsQuery='';return}const mealReview=candidates.some(c=>c.mealReview),title=mealReview?`Review meal (${candidates.length})`:`Results for "${esc(query||'this food')}"`;const addAll=mealReview?'<button type="button" data-add-all-food-candidates>Add all</button>':'';box.innerHTML=`<div class="lookup-results-head"><span>${title}</span><div class="lookup-head-actions">${addAll}<button type="button" data-clear-food-results>Clear</button></div></div>`+candidates.map((c,i)=>{const ing=ingredientFromCandidate(c),source=c.source||'Saved',unit=ingredientUnitLabel(ing),defaultAmount=Number(c.defaultAmount||0);return`<article class="lookup-card"><div><strong>${esc(ing.name)}</strong><span>${esc(source)} · ${fmt(safeNum(ing.calories))} kcal / ${esc(unit==='g'?'100g':unit)}</span>${mealReview&&defaultAmount>0?`<small>Will add ${fmt(defaultAmount)} ${esc(unit)}</small>`:''}<small>P ${fmt(safeNum(ing.protein))} · C ${fmt(safeNum(ing.carbs))} · F ${fmt(safeNum(ing.fat))} · Fi ${fmt(safeNum(ing.fibre))}</small>${c.note?`<small>${esc(c.note)}</small>`:''}</div><button type="button" data-use-food-candidate="${i}">${mealReview?'Add':'Use'}</button></article>`}).join('')}
function logCandidateToDay(c){const ing=upsertIngredient(ingredientFromCandidate(c));const amount=Number(c.defaultAmount||0)||lookupAmount()||(['item','scoop','can','pack'].includes(ing.unit)?1:100);const unit=ingredientUnitLabel(ing);addEntryToDay(`${ing.name} (${fmt(amount)} ${unit})`,ingredientMacros(ing,amount),[{name:ing.name,amount,unit}])}
