function manualMacroCandidate(){const name=lookupInputValue()||'Custom food';const m=emptyMacros();m.calories=Number(document.getElementById('manualCalories')?.value||0);m.protein=Number(document.getElementById('manualProtein')?.value||0);m.carbs=Number(document.getElementById('manualCarbs')?.value||0);m.fat=Number(document.getElementById('manualFat')?.value||0);m.fibre=Number(document.getElementById('manualFibre')?.value||0);m.addedSugar=Number(document.getElementById('manualAddedSugar')?.value||0);m.naturalSugar=Number(document.getElementById('manualNaturalSugar')?.value||0);m.totalSugar=m.addedSugar+m.naturalSugar;return{id:`custom-${slugify(name)}-${Date.now()}`,name,unit:'item',source:'Custom',defaultAmount:1,macros:m}}
