function productToCandidate(p){const n=p?.nutriments||{};const name=[p?.product_name,p?.brands].filter(Boolean).join(' · ').trim();const calories=safeNum(n['energy-kcal_100g']??n['energy-kcal']??n.energy_kcal_100g);if(!name||calories<=0)return null;return{id:`off-${p.code||slugify(name)}`,name,unit:'100g',source:'Open Food Facts',sourceId:p.code||'',note:'Total sugars are saved as natural sugar unless the source splits them.',macros:{calories,protein:safeNum(n.proteins_100g??n.proteins),carbs:safeNum(n.carbohydrates_100g??n.carbohydrates),fat:safeNum(n.fat_100g??n.fat),fibre:safeNum(n.fiber_100g??n.fiber),addedSugar:0,naturalSugar:safeNum(n.sugars_100g??n.sugars)}}}
async function searchOpenFoodFacts(query){const fields='code,product_name,brands,nutriments,serving_size,serving_quantity,quantity,countries_tags';const q=String(query||'').trim();if(!q)return[];const seen=new Set(),out=[];async function readUrl(url){const res=await fetch(url,{headers:{Accept:'application/json'}});if(!res.ok)throw new Error(`Open Food Facts ${res.status}`);return res.json()}if(/^\d{8,14}$/.test(q)){const data=await readUrl(`https://world.openfoodfacts.org/api/v2/product/${encodeURIComponent(q)}?fields=${encodeURIComponent(fields)}`);const c=productToCandidate(data.product);if(c&&!seen.has(c.id)){seen.add(c.id);out.push(c)}}const data=await readUrl(`https://world.openfoodfacts.org/cgi/search.pl?search_terms=${encodeURIComponent(q)}&search_simple=1&action=process&json=1&page_size=8&fields=${encodeURIComponent(fields)}`);(data.products||[]).forEach(p=>{const c=productToCandidate(p);if(c&&!seen.has(c.id)){seen.add(c.id);out.push(c)}});return out}
async function runOnlineFoodSearchLegacy(){const q=lookupInputValue();if(!q){showToast('Type a food first');return}const local=findIngredientMatches(q,4).map(i=>candidateFromIngredient(i));renderFoodLookupCandidates(local);setLookupStatus('Searching online...');try{const online=await searchOpenFoodFacts(q);const combined=[...local,...online];renderFoodLookupCandidates(combined);setLookupStatus(combined.length?`${combined.length} match${combined.length===1?'':'es'} found`:'No online matches found')}catch(e){console.error(e);setLookupStatus('Online lookup failed. Try saved foods or custom macros.')}}
function cleanFoodCandidate(c){if(!c||!c.name)return null;const m={...emptyMacros(),...(c.macros||{})};m.calories=safeNum(m.calories);m.protein=safeNum(m.protein);m.carbs=safeNum(m.carbs);m.fat=safeNum(m.fat);m.fibre=safeNum(m.fibre);m.addedSugar=safeNum(m.addedSugar);m.naturalSugar=safeNum(m.naturalSugar);m.totalSugar=m.addedSugar+m.naturalSugar;if(m.calories<=0)return null;return{...c,unit:c.unit||'100g',macros:m}}
function dedupeFoodCandidates(candidates,limit=14){const seen=new Set(),out=[];(candidates||[]).forEach(raw=>{const c=cleanFoodCandidate(raw);if(!c)return;const key=c.sourceId?`${c.source||''}:${c.sourceId}`:`${c.name.toLowerCase().trim()}:${fmt(c.macros.calories)}`;if(seen.has(key))return;seen.add(key);out.push(c)});return out.slice(0,limit)}
async function searchFoodLookupProxy(query){const res=await fetch(FOOD_LOOKUP_FUNCTION_URL,{method:'POST',headers:{'Content-Type':'application/json',apikey:SUPABASE_ANON_KEY,Authorization:`Bearer ${SUPABASE_ANON_KEY}`},body:JSON.stringify({query,country:'GB'})});if(!res.ok)throw new Error(`Food lookup ${res.status}`);const data=await res.json();return{candidates:dedupeFoodCandidates(data.candidates||[]),providers:data.providers||[]}}
function lookupProviderText(providers,fallback=false){const active=(providers||[]).filter(p=>p.status==='ok'&&safeNum(p.count)>0).map(p=>p.name);if(active.length)return` via ${active.join(', ')}`;return fallback?' via Open Food Facts fallback':''}
function lookupHasProviderError(providers){return(providers||[]).some(p=>p.status==='error')}
async function bestMealCandidate(item){const local=findIngredientForMealName(item.name);if(local)return withParsedMealAmount(candidateFromIngredient(local),item,true);try{const remote=await searchFoodLookupProxy(item.name);if(remote.candidates[0])return withParsedMealAmount(remote.candidates[0],item,true)}catch(e){console.warn('Meal proxy lookup failed',e)}try{const online=await searchOpenFoodFacts(item.name);if(online[0])return withParsedMealAmount(online[0],item,true)}catch(e){console.warn('Meal fallback lookup failed',e)}return null}
async function runMealReview(query,items){setLookupStatus(`Reviewing ${items.length} foods...`);renderFoodLookupCandidates([],query);const candidates=[],missing=[];for(const item of items){const candidate=await bestMealCandidate(item);if(lookupInputValue()!==query)return;if(candidate)candidates.push(candidate);else missing.push(item.name)}renderFoodLookupCandidates(candidates,query);const ready=candidates.length?`${candidates.length} food${candidates.length===1?'':'s'} ready to approve`:'';const miss=missing.length?`No match for ${missing.join(', ')}`:'';setLookupStatus([ready,miss].filter(Boolean).join('. ')||'No foods found')}
async function runOnlineFoodSearch(){const original=lookupInputValue();if(!original){showToast('Type a food first');return}const mealItems=parseMealItems(original);if(mealItems.length>1){await runMealReview(original,mealItems);return}const parsedItem=mealItems[0]||null,q=(parsedItem?.name||original).trim();if(!q){showToast('Type a food first');return}const local=findIngredientMatches(q,4).map(i=>withParsedMealAmount(candidateFromIngredient(i),parsedItem,false));renderFoodLookupCandidates(local,original);setLookupStatus('Searching databases...');try{const remote=await searchFoodLookupProxy(q);if(lookupInputValue()!==original)return;if(!remote.candidates.length&&lookupHasProviderError(remote.providers))throw new Error('Food database unavailable');const remoteCandidates=remote.candidates.map(c=>withParsedMealAmount(c,parsedItem,false));const combined=dedupeFoodCandidates([...local,...remoteCandidates]);renderFoodLookupCandidates(combined,original);setLookupStatus(combined.length?`${combined.length} match${combined.length===1?'':'es'} found${lookupProviderText(remote.providers)}`:'No database matches found')}catch(e){console.warn(e);try{const online=await searchOpenFoodFacts(q);if(lookupInputValue()!==original)return;const onlineCandidates=online.map(c=>withParsedMealAmount(c,parsedItem,false));const combined=dedupeFoodCandidates([...local,...onlineCandidates]);renderFoodLookupCandidates(combined,original);setLookupStatus(combined.length?`${combined.length} match${combined.length===1?'':'es'} found${lookupProviderText([],true)}`:'No online matches found')}catch(err){console.error(err);if(lookupInputValue()===original)setLookupStatus('Food databases are temporarily unavailable. Try again or add custom macros.')}}}
function renderIngredientSuggestions(input){const wrap=input.closest('.ingredient-lookup');const box=wrap?.querySelector('.ingredient-suggestions');if(!box)return;const matches=findIngredientMatches(input.value,7);if(!input.value.trim()||!matches.length){box.classList.add('hidden');box.innerHTML='';return}box.classList.remove('hidden');box.innerHTML=matches.map(i=>`<button type="button" data-pick-ingredient="${esc(i.id)}"><span>${esc(i.name)}</span><small>${fmt(safeNum(i.calories))} kcal · ${esc(ingredientUnitLabel(i)==='g'?'100g':ingredientUnitLabel(i))}</small></button>`).join('')}
function setupIngredientLookupSuggestions(){document.addEventListener('input',e=>{const input=e.target.closest('.ingredient-lookup input[type="search"]');if(input){renderIngredientSuggestions(input);if(input.id==='foodLookupInput')updateFoodLookupUnit()}});document.addEventListener('focusin',e=>{const input=e.target.closest('.ingredient-lookup input[type="search"]');if(input)renderIngredientSuggestions(input)});document.addEventListener('click',e=>{const pick=e.target.closest('[data-pick-ingredient]');if(pick){const wrap=pick.closest('.ingredient-lookup');const input=wrap?.querySelector('input[type="search"]');const ing=ingredientMap.get(pick.dataset.pickIngredient);if(input&&ing){input.value=ing.name;input.dispatchEvent(new Event('input',{bubbles:true}));wrap.querySelector('.ingredient-suggestions')?.classList.add('hidden')}return}if(!e.target.closest('.ingredient-lookup'))document.querySelectorAll('.ingredient-suggestions').forEach(x=>x.classList.add('hidden'))})}
function parseNutritionText(text){const raw=String(text||'').replace(/,/g,'.');function valueFor(names,unit='g'){for(const name of names){const re=new RegExp(`${name}[^\\n\\d]{0,35}(\\d+(?:\\.\\d+)?)\\s*${unit}`,'i');const m=raw.match(re);if(m)return Number(m[1])}return 0}const kcal=(raw.match(/(?:energy|calories)[^\n\d]{0,45}(\d+(?:\.\d+)?)\s*kcal/i)||raw.match(/(\d+(?:\.\d+)?)\s*kcal/i));const m=emptyMacros();m.calories=kcal?Number(kcal[1]):0;m.protein=valueFor(['protein']);m.carbs=valueFor(['carbohydrates?','carbs']);m.fat=valueFor(['fat']);m.fibre=valueFor(['fibre','fiber']);m.naturalSugar=valueFor(['sugars?']);m.totalSugar=m.naturalSugar;return m}
function loadScript(src){return new Promise((resolve,reject)=>{if(document.querySelector(`script[src="${src}"]`)){resolve();return}const s=document.createElement('script');s.src=src;s.async=true;s.onload=resolve;s.onerror=reject;document.head.appendChild(s)})}
async function handleLabelPhoto(file){if(!file)return;setLookupStatus('Reading label...');try{await loadScript('https://cdn.jsdelivr.net/npm/tesseract.js@5/dist/tesseract.min.js');if(!window.Tesseract)throw new Error('OCR library unavailable');const result=await window.Tesseract.recognize(file,'eng');const macros=parseNutritionText(result?.data?.text||'');if(!macros.calories&&!macros.protein&&!macros.carbs&&!macros.fat){setLookupStatus('Could not read nutrition values. Try a clearer photo.');return}const name=lookupInputValue()||'Scanned label';renderFoodLookupCandidates([{id:`scan-${slugify(name)}-${Date.now()}`,name,unit:'item',source:'Label scan',defaultAmount:1,note:'Review before using. OCR can misread labels.',macros}]);setLookupStatus('Label scanned')}catch(e){console.error(e);setLookupStatus('Camera scan failed. Try online search or custom macros.')}}
function setVoiceButtonListening(listening){foodVoiceListening=listening;const btn=document.getElementById('voiceFoodInput');if(!btn)return;btn.classList.toggle('listening',listening);btn.setAttribute('aria-pressed',String(listening));btn.textContent=listening?'Stop':'Voice'}
function voiceRecognitionCtor(){return window.SpeechRecognition||window.webkitSpeechRecognition||null}
function voiceTranscriptText(){return normalizeVoiceFoodText([foodVoiceFinalText,foodVoiceInterimText].filter(Boolean).join(' '))}
function voiceErrorMessage(error){if(error==='not-allowed'||error==='service-not-allowed'||error==='NotAllowedError')return'Microphone permission blocked.';if(error==='no-speech')return'No speech heard.';if(error==='audio-capture')return'Microphone unavailable.';if(error==='network')return'Voice recognition network error.';return'Voice transcription stopped.'}
function setVoicePanel(open){const panel=document.getElementById('foodVoicePanel');if(!panel)return;panel.classList.toggle('hidden',!open);document.body.classList.toggle('voice-panel-open',open)}
function resetVoiceMeter(){document.querySelectorAll('#foodVoiceMeter span').forEach((bar,i)=>bar.style.setProperty('--level',String(.18+(i%3)*.04)))}
function renderVoicePanel(status='Listening...'){const panel=document.getElementById('foodVoicePanel'),statusEl=document.getElementById('foodVoiceStatus'),textEl=document.getElementById('foodVoiceTranscript'),stopBtn=document.getElementById('foodVoiceStop'),findBtn=document.getElementById('foodVoiceFind');if(!panel)return;const transcript=voiceTranscriptText();setVoicePanel(true);panel.classList.toggle('listening',foodVoiceListening);panel.classList.toggle('has-text',!!transcript);if(statusEl)statusEl.textContent=status;if(textEl)textEl.textContent=transcript||'...';if(stopBtn)stopBtn.disabled=!foodVoiceListening;if(findBtn)findBtn.disabled=!transcript&&!lookupInputValue()}
function updateFoodInputFromVoice(){const input=document.getElementById('foodLookupInput'),transcript=voiceTranscriptText();if(!input||!transcript)return;const base=foodVoiceStartValue.trim(),joiner=base&& !/[,\n]$/.test(base)?', ':'';input.value=(base?base+joiner:'')+transcript;input.dispatchEvent(new Event('input',{bubbles:true}))}
function stopVoiceMeter(){resetVoiceMeter()}
function resetFoodVoiceSession(){if(foodVoiceStartTimer){clearTimeout(foodVoiceStartTimer);foodVoiceStartTimer=null}const recognition=foodVoiceRecognition;foodVoiceRecognition=null;if(recognition){recognition.onstart=null;recognition.onresult=null;recognition.onerror=null;recognition.onend=null;try{recognition.abort()}catch(e){console.warn(e)}}foodVoiceFinalText='';foodVoiceInterimText='';foodVoiceLastError='';foodVoiceCancelRequested=false;foodVoiceCloseAfterStop=false;foodVoiceReviewAfterStop=false;setVoiceButtonListening(false);stopVoiceMeter();setVoicePanel(false)}
function reviewSpokenFood(){const query=lookupInputValue();if(!query){showToast('Say a food first');return}setVoicePanel(false);runOnlineFoodSearch().then(()=>document.getElementById('foodLookupResults')?.scrollIntoView({block:'start',behavior:'smooth'}))}
function finalizeFoodVoice(){if(foodVoiceStartTimer){clearTimeout(foodVoiceStartTimer);foodVoiceStartTimer=null}const cancelled=foodVoiceCancelRequested,closePanel=foodVoiceCloseAfterStop,review=foodVoiceReviewAfterStop,error=foodVoiceLastError,hadText=!!voiceTranscriptText();foodVoiceRecognition=null;setVoiceButtonListening(false);stopVoiceMeter();foodVoiceCancelRequested=false;foodVoiceCloseAfterStop=false;foodVoiceReviewAfterStop=false;if(cancelled){const input=document.getElementById('foodLookupInput');if(input){input.value=foodVoiceStartValue;input.dispatchEvent(new Event('input',{bubbles:true}))}setLookupStatus('');setVoicePanel(false);return}if(error){renderVoicePanel(error);setLookupStatus(error);return}if(hadText){renderVoicePanel(review?'Building meal review...':'Ready to review');setLookupStatus(review?'Building meal review...':'Voice added. Tap Review meal.')}else{renderVoicePanel('No speech heard');setLookupStatus('No speech heard.')}if(closePanel||review)setVoicePanel(false);if(review)reviewSpokenFood()}
function stopFoodVoiceInput(cancel=false,closePanel=false,review=false){if(foodVoiceStartTimer){clearTimeout(foodVoiceStartTimer);foodVoiceStartTimer=null}foodVoiceCancelRequested=cancel;foodVoiceCloseAfterStop=closePanel;foodVoiceReviewAfterStop=review;if(cancel)foodVoiceReviewAfterStop=false;if(foodVoiceRecognition){try{cancel?foodVoiceRecognition.abort():foodVoiceRecognition.stop();return}catch(e){console.warn(e)}}finalizeFoodVoice()}
async function startFreeFoodVoiceInput(){const input=document.getElementById('foodLookupInput'),Recognition=voiceRecognitionCtor();if(!input)return;if(foodVoiceListening){stopFoodVoiceInput(false,true,true);return}resetFoodVoiceSession();if(!Recognition){input.focus();setLookupStatus('In-app voice is not supported on this browser.');renderVoicePanel('Voice unavailable');return}foodVoiceStartValue=input.value.trim();foodVoiceFinalText='';foodVoiceInterimText='';foodVoiceLastError='';foodVoiceCancelRequested=false;foodVoiceCloseAfterStop=false;foodVoiceReviewAfterStop=false;resetVoiceMeter();renderVoicePanel('Starting...');setVoiceButtonListening(true);const recognition=new Recognition();foodVoiceRecognition=recognition;recognition.lang='en-GB';recognition.continuous=false;recognition.interimResults=true;recognition.maxAlternatives=1;try{if('phrases'in recognition)recognition.phrases=ingredients.slice(0,80).map(i=>i.name)}catch(e){console.warn(e)}recognition.onstart=()=>{setVoiceButtonListening(true);renderVoicePanel('Listening...');setLookupStatus('Listening...')};recognition.onresult=e=>{let interim='';for(let i=e.resultIndex;i<e.results.length;i++){const text=e.results[i][0]?.transcript||'';if(e.results[i].isFinal)foodVoiceFinalText+=`${text} `;else interim+=text}foodVoiceInterimText=interim.trim();updateFoodInputFromVoice();renderVoicePanel('Transcribing...');setLookupStatus('Listening...')};recognition.onerror=e=>{foodVoiceLastError=voiceErrorMessage(e.error||e.name)};recognition.onend=finalizeFoodVoice;foodVoiceStartTimer=setTimeout(()=>{foodVoiceStartTimer=null;try{recognition.start()}catch(e){console.warn(e);foodVoiceLastError=voiceErrorMessage(e.name||e.message);finalizeFoodVoice()}},120)}
function setupFoodVoiceInput(){document.getElementById('voiceFoodInput')?.addEventListener('click',startFreeFoodVoiceInput);document.getElementById('foodVoiceStop')?.addEventListener('click',()=>stopFoodVoiceInput(false,true,true));document.getElementById('foodVoiceCancel')?.addEventListener('click',()=>stopFoodVoiceInput(true));document.getElementById('foodVoiceFind')?.addEventListener('click',()=>{if(foodVoiceListening){stopFoodVoiceInput(false,true,true);return}reviewSpokenFood()})}
function refreshAllRecipes(){recipes=baseRecipes.map(r=>({...r,ingredients:[...(recipeEdits[r.id]?.ingredients||r.ingredients||[])]})).concat(customRecipes)}
function persistRecipe(r){if(r.custom){customRecipes=customRecipes.map(x=>x.id===r.id?r:x);saveCustomRecipes()}else{recipeEdits[r.id]={...(recipeEdits[r.id]||{}),ingredients:r.ingredients};saveRecipeEdits()}}

function setRecipeBuilderOpen(open){const panel=document.getElementById('builderPanel'),btn=document.getElementById('toggleRecipeBuilder');if(!panel||!btn)return;panel.classList.toggle('hidden',!open);btn.setAttribute('aria-expanded',String(open));btn.textContent=open?'-':'+';if(open)document.getElementById('newRecipeName')?.focus()}
function setupRecipeBuilderToggle(){document.getElementById('toggleRecipeBuilder')?.addEventListener('click',()=>setRecipeBuilderOpen(document.getElementById('builderPanel')?.classList.contains('hidden')))}
function setupRecentFoodToggle(){document.getElementById('recentFoods')?.addEventListener('click',e=>{if(!e.target.closest('[data-toggle-recents]'))return;recentFoodsCollapsed=!recentFoodsCollapsed;saveRecentFoodsCollapsed();renderRecents()})}
function setupTabs(){document.querySelectorAll('.tab-button').forEach(btn=>btn.addEventListener('click',()=>{document.querySelectorAll('.tab-button').forEach(b=>b.classList.remove('active'));document.querySelectorAll('.tab-panel').forEach(p=>p.classList.remove('active'));btn.classList.add('active');document.getElementById(btn.dataset.tab)?.classList.add('active');if(btn.dataset.tab==='historyPanel')renderHistory();window.scrollTo({top:0,behavior:'smooth'})}))}
function refreshTagFilter(){const f=document.getElementById('tagFilter');const selected=f.value;const tags=[...new Set(recipes.flatMap(getRecipeTags))].sort((a,b)=>a.localeCompare(b));f.innerHTML='<option value="">All tags</option>';tags.forEach(t=>f.insertAdjacentHTML('beforeend',`<option value="${esc(t)}">${esc(t)}</option>`));f.value=tags.includes(selected)?selected:''}
function renderTagChips(r){return getRecipeTags(r).map(t=>`<span class="tag">${esc(t)} <button type="button" class="tag-x" data-remove-tag="${esc(r.id)}" data-tag="${esc(t)}">×</button></span>`).join('')}

function renderRecipes(){const q=document.getElementById('search').value.toLowerCase().trim();const tag=document.getElementById('tagFilter').value;const grid=document.getElementById('recipeGrid');grid.innerHTML='';const found=recipes.filter(r=>{const tags=getRecipeTags(r);const ing=(r.ingredients||[]).map(x=>ingredientMap.get(x.ingredientId)?.name||x.ingredientId);const txt=[r.name,...tags,...ing,...(r.method||[]),...(r.seasoning||[])].join(' ').toLowerCase();return(!q||txt.includes(q))&&(!tag||tags.includes(tag))});if(!found.length){grid.innerHTML='<article class="card"><h2>No recipes found</h2><p class="seasoning">Try another keyword or tag.</p></article>';return}found.forEach(r=>{const isOpen=openRecipes.has(r.id);const card=document.createElement('article');card.className=`card recipe-card ${isOpen?'':'collapsed'}`;const rows=(r.ingredients||[]).map((x,i)=>{const ing=ingredientMap.get(x.ingredientId);return`<tr><td>${esc(ing?ing.name:x.ingredientId)}</td><td><input type="number" min="0" step="1" value="${x.amount}" data-recipe="${esc(r.id)}" data-ingredient="${esc(x.ingredientId)}" data-row-index="${i}"></td><td>${esc(ingredientUnitLabel(ing))}</td><td><button type="button" class="small-button" data-remove-ingredient="${esc(r.id)}" data-index="${i}">Remove</button></td></tr>`}).join('');card.innerHTML=`<div class="recipe-head"><div><h2>${esc(r.name)}</h2><div class="macro-line compact" id="macros-${esc(r.id)}"></div></div><button type="button" class="toggle-recipe" data-toggle-recipe data-recipe-id="${esc(r.id)}">${isOpen?'−':'＋'}</button></div><p class="seasoning" id="sugar-${esc(r.id)}"></p><div class="recipe-details"><div class="tags">${renderTagChips(r)}</div><div class="tag-editor"><input type="text" placeholder="Add tag" data-tag-input="${esc(r.id)}"><button type="button" data-add-tag="${esc(r.id)}">Add</button></div><table><thead><tr><th>Ingredient</th><th>Amount</th><th>Unit</th><th></th></tr></thead><tbody>${rows}</tbody></table><div class="ingredient-editor"><input type="search" list="ingredientDatalist" placeholder="Add ingredient" data-add-ingredient-name="${esc(r.id)}"><input type="number" min="0" step="1" value="100" data-add-ingredient-amount="${esc(r.id)}"><button type="button" data-add-ingredient="${esc(r.id)}">Add item</button></div><div class="card-actions"><button type="button" data-add-recipe-to-day="${esc(r.id)}">Add recipe to day</button>${r.custom?`<button type="button" data-delete-custom-recipe="${esc(r.id)}">Delete recipe</button>`:''}</div>${(r.seasoning||[]).length?`<p class="seasoning"><strong>Seasoning:</strong> ${r.seasoning.map(esc).join(', ')}</p>`:''}<ol class="method">${(r.method||[]).map(s=>`<li>${esc(s)}</li>`).join('')}</ol></div>`;grid.appendChild(card)});document.querySelectorAll('input[data-recipe]').forEach(i=>i.addEventListener('input',handleIngredientAmountInput));updateAllMacros()}
function handleIngredientAmountInput(e){const r=recipes.find(x=>x.id===e.target.dataset.recipe);if(!r)return;const i=Number(e.target.dataset.rowIndex);if(r.ingredients[i])r.ingredients[i].amount=Number(e.target.value||0);persistRecipe(r);updateAllMacros()}
function updateAllMacros(){recipes.forEach(r=>{const box=document.getElementById(`macros-${r.id}`);const sugar=document.getElementById(`sugar-${r.id}`);if(!box)return;const t=recipeMacros(r);box.innerHTML=macroHTML(t);sugar.textContent=sugarText(t)});updateIngredientCalculator();renderDailyTracker();renderBuilder();renderHistory()}
function populateIngredientDatalist(){document.getElementById('ingredientDatalist').innerHTML=ingredients.slice().sort((a,b)=>a.name.localeCompare(b.name)).map(i=>`<option value="${esc(i.name)}"></option>`).join('')}
function populateIngredientSelect(){const filter=document.getElementById('ingredientSearch').value.toLowerCase().trim();const s=document.getElementById('ingredientSelect');const prev=s.value;const filtered=ingredients.slice().sort((a,b)=>a.name.localeCompare(b.name)).filter(i=>!filter||i.name.toLowerCase().includes(filter)||i.id.toLowerCase().includes(filter));s.innerHTML='';filtered.forEach(i=>s.insertAdjacentHTML('beforeend',`<option value="${esc(i.id)}">${esc(i.name)}</option>`));if(filtered.some(i=>i.id===prev))s.value=prev;else if(filtered[0])s.value=filtered[0].id;updateIngredientCalculator()}
function updateIngredientCalculator(){const s=document.getElementById('ingredientSelect');if(!s)return;const id=s.value;const amount=Number(document.getElementById('ingredientAmount').value||0);const ing=ingredientMap.get(id);const unit=document.getElementById('ingredientUnit');if(!ing){unit.textContent='';document.getElementById('ingredientResult').innerHTML='<p class="seasoning">No matching ingredient found.</p>';return}unit.textContent=ingredientUnitLabel(ing);const m=ingredientMacros(ing,amount);document.getElementById('ingredientResult').innerHTML=macroHTML(m)+`<p class="seasoning">${sugarText(m)}</p>`}

function getSelectedDate(){return document.getElementById('trackerDate').value||todayLocal()}
function getHistoryDate(){return document.getElementById('historyDate')?.value||getSelectedDate()}
function getEntriesForDate(date){return dailyLog[date]?.entries||[]}
function totalsForEntries(entries){const t=emptyMacros();entries.forEach(e=>addMacros(t,e.macros||emptyMacros()));return t}
function makeEntry(label,macros,details=[]){return{id:`entry-${Date.now()}-${Math.random().toString(16).slice(2)}`,label,macros,details,createdAt:new Date().toISOString()}}
function addEntryToDay(label,macros,details=[]){const date=getSelectedDate();if(!dailyLog[date])dailyLog[date]={entries:[]};const entry=makeEntry(label,macros,details);dailyLog[date].entries.push(entry);saveDailyLog();renderDailyTracker();renderHistory();if(supabaseUser){saveEntryToSupabase(date,entry)}else{showToast('Saved locally')}}
function renderProgress(name,value,target,suffix='g'){const pct=target>0?Math.min(value/target*100,120):0;const label=name==='Calories'?`${fmt(value)} / ${fmt(target)} kcal`:`${fmt(value)} / ${fmt(target)}${suffix}`;return`<div class="progress-row"><div><strong>${name}</strong><span>${label}</span></div><div class="progress-track"><div class="progress-fill" style="width:${pct}%"></div></div></div>`}
function renderEntryDetails(e){if(!e.details?.length)return'';return`<div class="entry-details ${openEntries.has(e.id)?'':'hidden'}" id="details-${esc(e.id)}">${e.details.map(d=>`<div><span>${esc(d.name)}</span><strong>${fmt(d.amount)} ${esc(d.unit)}</strong></div>`).join('')}</div>`}
function entryHTML(e,allowDelete=true){const m=e.macros||{};const hasDetails=e.details?.length;return`<div class="entry-card"><div class="entry"><div class="entry-main"><span class="entry-name">${esc(e.label)}</span><span class="entry-sub">P ${fmt(m.protein)} · C ${fmt(m.carbs)} · F ${fmt(m.fat)} · Fi ${fmt(m.fibre)}</span></div><span class="entry-cal">${fmt(m.calories)}<small>kcal</small></span>${hasDetails?`<button class="entry-btn" type="button" data-toggle-entry="${esc(e.id)}" aria-label="Toggle details">${openEntries.has(e.id)?'−':'＋'}</button>`:''}${allowDelete?`<button class="entry-btn danger" type="button" data-delete-entry="${esc(e.id)}" aria-label="Delete">×</button>`:''}</div>${renderEntryDetails(e)}</div>`}
function renderMacroBar(name,value,target,varName){const t=safeNum(target);const pct=t>0?Math.min(value/t*100,100):0;const over=t>0&&value>t;return`<div class="mbar${over?' over':''}"><div class="mbar-top"><span>${name}</span><span>${fmt(value)} / ${fmt(t)}g</span></div><div class="mbar-track"><div class="mbar-fill" style="width:${pct}%;background:var(--${varName})"></div></div></div>`}
function renderCalorieSummary(totals){const target=safeNum(macroTargets.calories);const eaten=totals.calories;const ring=document.getElementById('calRing');const rem=document.getElementById('calRemaining');const remLabel=document.getElementById('calRemainingLabel');if(target>0){const remaining=target-eaten;const pct=Math.min(eaten/target*100,100);if(ring){ring.style.setProperty('--pct',pct);ring.classList.toggle('over',eaten>target)}if(rem)rem.textContent=fmt(Math.round(Math.abs(remaining)));if(remLabel)remLabel.textContent=remaining<0?'over':'left'}else{if(ring){ring.style.setProperty('--pct',0);ring.classList.remove('over')}if(rem)rem.textContent=fmt(Math.round(eaten));if(remLabel)remLabel.textContent='kcal'}const c=document.getElementById('calConsumed');if(c)c.textContent=fmt(Math.round(eaten));const g=document.getElementById('calTarget');if(g)g.textContent=fmt(target)}
function renderDailyTracker(){const trackerDate=document.getElementById('trackerDate');if(!trackerDate)return;const date=getSelectedDate(),entries=getEntriesForDate(date),totals=totalsForEntries(entries);renderCalorieSummary(totals);const bars=document.getElementById('macroBars');if(bars)bars.innerHTML=renderMacroBar('Protein',totals.protein,macroTargets.protein,'protein')+renderMacroBar('Carbs',totals.carbs,macroTargets.carbs,'carbs')+renderMacroBar('Fat',totals.fat,macroTargets.fat,'fat')+renderMacroBar('Fibre',totals.fibre,macroTargets.fibre,'fibre');document.getElementById('dailyEntries').innerHTML=entries.length?entries.map(e=>entryHTML(e,true)).join(''):'<p class="empty">Nothing logged yet. Add your first item above.</p>';renderRecents()}
function renderCalorieChart(selectedDate,avgId,chartId){const days=Array.from({length:7},(_,i)=>shiftDate(selectedDate,i-6));const rows=days.map(date=>({date,calories:totalsForEntries(getEntriesForDate(date)).calories}));const logged=rows.filter(r=>r.calories>0);const avg=logged.length?logged.reduce((s,r)=>s+r.calories,0)/logged.length:0;const avgEl=document.getElementById(avgId);if(avgEl)avgEl.innerHTML=`<strong>Weekly average:</strong> ${fmt(avg)} kcal/day across ${logged.length||0} logged day${logged.length===1?'':'s'}.`;const chartEl=document.getElementById(chartId);if(!chartEl)return;const max=Math.max(macroTargets.calories,...rows.map(r=>r.calories),1);chartEl.innerHTML=rows.map(r=>{const h=Math.max(5,r.calories/max*100);return`<div class="bar-wrap"><div class="bar-value">${fmt(r.calories)}</div><div class="bar-shell"><div class="bar" style="height:${h}%"></div></div><span>${shortDateLabel(r.date)}</span></div>`}).join('')}
function renderHistory(){const dInput=document.getElementById('historyDate');if(!dInput)return;if(!dInput.value)dInput.value=getSelectedDate();const date=getHistoryDate();const entries=getEntriesForDate(date);const totals=totalsForEntries(entries);const label=document.getElementById('historyToday');if(label){label.textContent=longDateLabel(date);label.title='Jump to today'}document.getElementById('historyTotals').innerHTML=macroHTML(totals);document.getElementById('historyWeeklyAverage').innerHTML='';renderCalorieChart(date,'historyWeeklyAverage','historyChart');document.getElementById('historyEntries').innerHTML=`<h3>${esc(longDateLabel(date))}</h3>`+(entries.length?entries.map(e=>entryHTML(e,false)).join(''):'<p class="seasoning">No entries logged for this day.</p>')}
function saveTargetInputs(){macroTargets={calories:Number(document.getElementById('targetCalories').value||0),protein:Number(document.getElementById('targetProtein').value||0),carbs:Number(document.getElementById('targetCarbs').value||0),fat:Number(document.getElementById('targetFat').value||0),fibre:Number(document.getElementById('targetFibre').value||0)};saveTargets();renderDailyTracker();renderHistory()}
function hydrateTargetInputs(){document.getElementById('targetCalories').value=macroTargets.calories;document.getElementById('targetProtein').value=macroTargets.protein;document.getElementById('targetCarbs').value=macroTargets.carbs;document.getElementById('targetFat').value=macroTargets.fat;document.getElementById('targetFibre').value=macroTargets.fibre}
function renderBuilder(){const list=document.getElementById('builderIngredients'),totalsBox=document.getElementById('builderTotals');if(!list||!totalsBox)return;list.innerHTML=builderIngredients.length?builderIngredients.map((x,i)=>{const ing=ingredientMap.get(x.ingredientId);return`<div class="entry"><span>${esc(ing?.name||x.ingredientId)}</span><span>${fmt(x.amount)} ${esc(ingredientUnitLabel(ing))}</span><button type="button" data-builder-remove="${i}">×</button></div>`}).join(''):'<p class="seasoning">No ingredients added yet.</p>';totalsBox.innerHTML=macroHTML(recipeMacrosFromIngredients(builderIngredients))}

function rowToEntry(row){const m={calories:safeNum(row.calories),protein:safeNum(row.protein),carbs:safeNum(row.carbs),fat:safeNum(row.fat),fibre:safeNum(row.fibre),addedSugar:safeNum(row.added_sugar),naturalSugar:safeNum(row.natural_sugar),totalSugar:0};m.totalSugar=m.addedSugar+m.naturalSugar;return{id:row.id,label:row.label,macros:m,details:Array.isArray(row.details)?row.details:[],createdAt:row.created_at}}
function rowsToLog(rows){const log={};(rows||[]).forEach(row=>{const date=row.entry_date;if(!log[date])log[date]={entries:[]};log[date].entries.push(rowToEntry(row))});return log}
function entryToRow(date,entry){const m=entry.macros||{};return{user_id:supabaseUser.id,entry_date:date,label:entry.label,calories:safeNum(m.calories),protein:safeNum(m.protein),carbs:safeNum(m.carbs),fat:safeNum(m.fat),fibre:safeNum(m.fibre),added_sugar:safeNum(m.addedSugar),natural_sugar:safeNum(m.naturalSugar),details:entry.details||[],created_at:entry.createdAt||new Date().toISOString()}}
async function setupSupabase(){try{if(!window.supabase){renderAuthBox('Sync library did not load');return}supabaseClient=window.supabase.createClient(SUPABASE_URL,SUPABASE_ANON_KEY,{auth:{persistSession:true,autoRefreshToken:true,detectSessionInUrl:true}});const {data:{session}}=await supabaseClient.auth.getSession();supabaseUser=session?.user||null;supabaseReady=true;renderAuthBox();supabaseClient.auth.onAuthStateChange(async(_,session)=>{supabaseUser=session?.user||null;renderAuthBox();if(supabaseUser){await loadSupabaseEntries();await syncUnsyncedLocalEntries();renderDailyTracker();renderHistory()}})}catch(e){console.error(e);renderAuthBox('Sync unavailable')}}
function renderAuthBox(error=''){let box=document.getElementById('authBox');if(!box){box=document.createElement('div');box.id='authBox';box.className='auth-box';document.querySelector('header')?.after(box)}if(error){box.className='auth-box';box.innerHTML=`<small>${esc(error)} · entries still save locally</small>`;return}if(supabaseUser){box.className='auth-box synced';box.innerHTML=`<small>Logged in as ${esc(supabaseUser.email||'your account')}</small><button id="authSignOut" type="button">Sign out</button>`;document.getElementById('authSignOut')?.addEventListener('click',async()=>{await supabaseClient.auth.signOut();showToast('Signed out')});return}box.className='auth-box';box.innerHTML='<input id="authEmail" type="email" placeholder="Email" autocomplete="username"><input id="authPassword" type="password" placeholder="Password" autocomplete="current-password"><button id="authLogin" type="button">Login</button><button id="authSignUp" type="button">Create account</button><small>Log in to sync</small>';document.getElementById('authLogin')?.addEventListener('click',passwordLogin);document.getElementById('authSignUp')?.addEventListener('click',passwordSignUp);document.getElementById('authPassword')?.addEventListener('keydown',e=>{if(e.key==='Enter')passwordLogin()})}
function readAuthCreds(){const email=document.getElementById('authEmail')?.value.trim();const password=document.getElementById('authPassword')?.value||'';if(!email||!password){showToast('Enter email and password');return null}return{email,password}}
async function passwordLogin(){const creds=readAuthCreds();if(!creds)return;try{const {error}=await supabaseClient.auth.signInWithPassword(creds);if(error)throw error;showToast('Logged in')}catch(e){console.error(e);showToast('Supabase error: '+(e.message||e))}}
async function passwordSignUp(){const creds=readAuthCreds();if(!creds)return;try{const {data,error}=await supabaseClient.auth.signUp(creds);if(error)throw error;if(data.session){showToast('Account created')}else{showToast('Check email to confirm')}}catch(e){console.error(e);showToast('Supabase error: '+(e.message||e))}}
async function loadSupabaseEntries(){if(!supabaseClient||!supabaseUser)return;try{const {data,error}=await supabaseClient.from('daily_entries').select('*').order('entry_date',{ascending:true}).order('created_at',{ascending:true});if(error)throw error;dailyLog=mergeLogs(dailyLog,rowsToLog(data));saveDailyLog()}catch(e){console.error(e);showToast('Supabase error: '+(e.message||e))}}
async function saveEntryToSupabase(date,entry,silent=false){if(!supabaseClient||!supabaseUser)return;try{const {data,error}=await supabaseClient.from('daily_entries').insert(entryToRow(date,entry)).select().single();if(error)throw error;const synced=rowToEntry(data);Object.assign(entry,synced);saveDailyLog();if(!silent){renderDailyTracker();renderHistory();showToast('Synced')}}catch(e){console.error(e);if(!silent)showToast('Supabase error: '+(e.message||e))}}
async function syncUnsyncedLocalEntries(){if(!supabaseClient||!supabaseUser)return;for(const[date,data]of Object.entries(dailyLog)){for(const entry of(data.entries||[])){if(!isUUID(entry.id)){await saveEntryToSupabase(date,entry,true)}}}saveDailyLog()}
async function deleteSupabaseEntry(id){if(!supabaseClient||!supabaseUser||!isUUID(id))return;try{const {error}=await supabaseClient.from('daily_entries').delete().eq('id',id);if(error)throw error}catch(e){console.error(e);showToast('Supabase error: '+(e.message||e))}}

function handleRecipeGridClick(e){const toggle=e.target.closest('[data-toggle-recipe]'),add=e.target.closest('[data-add-tag]'),remTag=e.target.closest('[data-remove-tag]'),addIng=e.target.closest('[data-add-ingredient]'),remIng=e.target.closest('[data-remove-ingredient]'),addDay=e.target.closest('[data-add-recipe-to-day]'),del=e.target.closest('[data-delete-custom-recipe]');if(toggle){const id=toggle.dataset.recipeId;const card=toggle.closest('.recipe-card');const open=card.classList.toggle('collapsed')===false;if(open)openRecipes.add(id);else openRecipes.delete(id);saveOpenRecipes();toggle.textContent=open?'−':'＋';return}if(add){const id=add.dataset.addTag,r=recipes.find(x=>x.id===id),input=document.querySelector(`[data-tag-input="${id}"]`),tag=normalizeTag(input.value);if(r&&tag){setRecipeTags(id,[...getRecipeTags(r),tag]);openRecipes.add(id);saveOpenRecipes();refreshTagFilter();renderRecipes()}}if(remTag){const id=remTag.dataset.removeTag,r=recipes.find(x=>x.id===id);if(r){setRecipeTags(id,getRecipeTags(r).filter(t=>t!==remTag.dataset.tag));openRecipes.add(id);saveOpenRecipes();refreshTagFilter();renderRecipes()}}if(addIng){const id=addIng.dataset.addIngredient,r=recipes.find(x=>x.id===id),name=document.querySelector(`[data-add-ingredient-name="${id}"]`),amount=document.querySelector(`[data-add-ingredient-amount="${id}"]`),ing=findIngredientByInput(name.value);if(r&&ing){r.ingredients.push({ingredientId:ing.id,amount:Number(amount.value||0)});persistRecipe(r);openRecipes.add(id);saveOpenRecipes();renderRecipes();showToast('Added')}else alert('Ingredient not found. Try typing the ingredient exactly as it appears in the list.')}if(remIng){const id=remIng.dataset.removeIngredient,r=recipes.find(x=>x.id===id),idx=Number(remIng.dataset.index);if(r&&r.ingredients[idx]){r.ingredients.splice(idx,1);persistRecipe(r);openRecipes.add(id);saveOpenRecipes();renderRecipes()}}if(addDay){const r=recipes.find(x=>x.id===addDay.dataset.addRecipeToDay);if(r){const items=currentRecipeItems(r);addEntryToDay(r.name,recipeMacrosFromIngredients(items),itemDetails(items))}}if(del){const id=del.dataset.deleteCustomRecipe;customRecipes=customRecipes.filter(r=>r.id!==id);delete customTags[id];openRecipes.delete(id);saveOpenRecipes();saveCustomTags();saveCustomRecipes();refreshAllRecipes();refreshTagFilter();renderRecipes()}}
function setupEventsLegacy(){setupTabs();document.getElementById('search').addEventListener('input',renderRecipes);document.getElementById('tagFilter').addEventListener('change',renderRecipes);document.getElementById('ingredientSearch').addEventListener('input',populateIngredientSelect);document.getElementById('ingredientSelect').addEventListener('change',updateIngredientCalculator);document.getElementById('ingredientAmount').addEventListener('input',updateIngredientCalculator);document.getElementById('addIngredientToDay').addEventListener('click',()=>{const ing=ingredientMap.get(document.getElementById('ingredientSelect').value);const amount=Number(document.getElementById('ingredientAmount').value||0);if(ing)addEntryToDay(`${ing.name} (${fmt(amount)} ${ingredientUnitLabel(ing)})`,ingredientMacros(ing,amount),[{name:ing.name,amount,unit:ingredientUnitLabel(ing)}])});document.getElementById('recipeGrid').addEventListener('click',handleRecipeGridClick);document.getElementById('trackerDate').addEventListener('change',()=>{renderDailyTracker();const h=document.getElementById('historyDate');if(h&&!h.value)h.value=getSelectedDate();renderHistory()});document.getElementById('dayPrev')?.addEventListener('click',()=>{document.getElementById('trackerDate').value=shiftDate(getSelectedDate(),-1);renderDailyTracker()});document.getElementById('dayNext')?.addEventListener('click',()=>{document.getElementById('trackerDate').value=shiftDate(getSelectedDate(),1);renderDailyTracker()});document.getElementById('editGoals')?.addEventListener('click',()=>{document.getElementById('goalsPanel')?.classList.toggle('hidden')});['targetCalories','targetProtein','targetCarbs','targetFat','targetFibre'].forEach(id=>document.getElementById(id).addEventListener('input',saveTargetInputs));document.getElementById('historyDate')?.addEventListener('change',renderHistory);document.getElementById('historyPrev')?.addEventListener('click',()=>{document.getElementById('historyDate').value=shiftDate(getHistoryDate(),-1);renderHistory()});document.getElementById('historyNext')?.addEventListener('click',()=>{document.getElementById('historyDate').value=shiftDate(getHistoryDate(),1);renderHistory()});document.getElementById('historyToday')?.addEventListener('click',()=>{document.getElementById('historyDate').value=todayLocal();renderHistory()});document.getElementById('addManualEntry').addEventListener('click',()=>{const label=document.getElementById('manualName').value.trim()||'Manual entry';const m=emptyMacros();m.calories=Number(document.getElementById('manualCalories').value||0);m.protein=Number(document.getElementById('manualProtein').value||0);m.carbs=Number(document.getElementById('manualCarbs').value||0);m.fat=Number(document.getElementById('manualFat').value||0);m.fibre=Number(document.getElementById('manualFibre').value||0);m.addedSugar=Number(document.getElementById('manualAddedSugar').value||0);m.naturalSugar=Number(document.getElementById('manualNaturalSugar').value||0);m.totalSugar=m.addedSugar+m.naturalSugar;addEntryToDay(label,m);['manualName','manualCalories','manualProtein','manualCarbs','manualFat','manualFibre','manualAddedSugar','manualNaturalSugar'].forEach(id=>document.getElementById(id).value='')});function entryClick(e){const t=e.target.closest('[data-toggle-entry]');if(t){const id=t.dataset.toggleEntry;if(openEntries.has(id))openEntries.delete(id);else openEntries.add(id);renderDailyTracker();renderHistory();return}const b=e.target.closest('[data-delete-entry]');if(!b)return;const id=b.dataset.deleteEntry;const date=getSelectedDate();const entries=getEntriesForDate(date);const idx=entries.findIndex(x=>x.id===id);if(idx<0)return;const removed=entries[idx];entries.splice(idx,1);openEntries.delete(id);saveDailyLog();renderDailyTracker();renderHistory();deleteSupabaseEntry(id);showUndo('Entry deleted',()=>{if(!dailyLog[date])dailyLog[date]={entries:[]};const list=dailyLog[date].entries;list.splice(Math.min(idx,list.length),0,removed);saveDailyLog();renderDailyTracker();renderHistory();if(supabaseUser)saveEntryToSupabase(date,removed,true)})}document.getElementById('dailyEntries').addEventListener('click',entryClick);document.getElementById('historyEntries')?.addEventListener('click',entryClick);document.getElementById('recentFoods')?.addEventListener('click',e=>{const b=e.target.closest('[data-recent]');if(!b)return;const item=recentItems[Number(b.dataset.recent)];if(!item)return;const m={...emptyMacros(),...(item.macros||{})};m.totalSugar=safeNum(m.addedSugar)+safeNum(m.naturalSugar);addEntryToDay(item.label,m,(item.details||[]).map(d=>({...d})))});document.getElementById('addBuilderIngredient').addEventListener('click',()=>{const ing=findIngredientByInput(document.getElementById('newRecipeIngredientSearch').value);if(!ing){alert('Ingredient not found. Try typing the ingredient exactly as it appears in the list.');return}builderIngredients.push({ingredientId:ing.id,amount:Number(document.getElementById('newRecipeIngredientAmount').value||0)});document.getElementById('newRecipeIngredientSearch').value='';renderBuilder();showToast('Added')});document.getElementById('builderIngredients').addEventListener('click',e=>{const b=e.target.closest('[data-builder-remove]');if(!b)return;builderIngredients.splice(Number(b.dataset.builderRemove),1);renderBuilder()});document.getElementById('saveNewRecipe').addEventListener('click',()=>{const name=document.getElementById('newRecipeName').value.trim();if(!name){alert('Add a recipe name first.');return}if(!builderIngredients.length){alert('Add at least one ingredient.');return}const id=`custom-${slugify(name)}-${Date.now()}`;const tags=document.getElementById('newRecipeTags').value.split(',').map(normalizeTag).filter(Boolean);const method=document.getElementById('newRecipeMethod').value.split('\n').map(s=>s.trim()).filter(Boolean);customRecipes.push({id,name,tags,ingredients:builderIngredients,method,seasoning:[],custom:true});saveCustomRecipes();builderIngredients=[];['newRecipeName','newRecipeTags','newRecipeIngredientSearch','newRecipeMethod'].forEach(id=>document.getElementById(id).value='');document.getElementById('newRecipeIngredientAmount').value=100;refreshAllRecipes();refreshTagFilter();renderBuilder();renderRecipes();showToast('Saved')})}

function setupEvents(){
  setupTabs();
  setupIngredientLookupSuggestions();
  document.getElementById('search').addEventListener('input',renderRecipes);
  document.getElementById('tagFilter').addEventListener('change',renderRecipes);
  document.getElementById('ingredientSearch').addEventListener('input',populateIngredientSelect);
  document.getElementById('ingredientSelect').addEventListener('change',updateIngredientCalculator);
  document.getElementById('ingredientAmount').addEventListener('input',updateIngredientCalculator);
  document.getElementById('addIngredientToDay').addEventListener('click',()=>{
    const ing=ingredientMap.get(document.getElementById('ingredientSelect').value);
    const amount=Number(document.getElementById('ingredientAmount').value||0);
    if(ing)addEntryToDay(`${ing.name} (${fmt(amount)} ${ingredientUnitLabel(ing)})`,ingredientMacros(ing,amount),[{name:ing.name,amount,unit:ingredientUnitLabel(ing)}]);
  });
  document.getElementById('recipeGrid').addEventListener('click',handleRecipeGridClick);
  document.getElementById('trackerDate').addEventListener('change',()=>{renderDailyTracker();const h=document.getElementById('historyDate');if(h&&!h.value)h.value=getSelectedDate();renderHistory()});
  document.getElementById('dayPrev')?.addEventListener('click',()=>{document.getElementById('trackerDate').value=shiftDate(getSelectedDate(),-1);renderDailyTracker()});
  document.getElementById('dayNext')?.addEventListener('click',()=>{document.getElementById('trackerDate').value=shiftDate(getSelectedDate(),1);renderDailyTracker()});
  document.getElementById('editGoals')?.addEventListener('click',()=>{document.getElementById('goalsPanel')?.classList.toggle('hidden')});
  ['targetCalories','targetProtein','targetCarbs','targetFat','targetFibre'].forEach(id=>document.getElementById(id).addEventListener('input',saveTargetInputs));
  document.getElementById('historyDate')?.addEventListener('change',renderHistory);
  document.getElementById('historyPrev')?.addEventListener('click',()=>{document.getElementById('historyDate').value=shiftDate(getHistoryDate(),-1);renderHistory()});
  document.getElementById('historyNext')?.addEventListener('click',()=>{document.getElementById('historyDate').value=shiftDate(getHistoryDate(),1);renderHistory()});
  document.getElementById('historyToday')?.addEventListener('click',()=>{document.getElementById('historyDate').value=todayLocal();renderHistory()});
  document.getElementById('foodLookupInput')?.addEventListener('input',()=>{updateFoodLookupUnit();setLookupStatus('');if(foodLookupResultsQuery&&lookupInputValue()!==foodLookupResultsQuery)renderFoodLookupCandidates([])});
  document.getElementById('foodLookupInput')?.addEventListener('keydown',e=>{if(e.key==='Enter'){e.preventDefault();runOnlineFoodSearch()}});
  document.getElementById('addSavedFoodToDay')?.addEventListener('click',()=>{
    const items=parseMealItems(lookupInputValue());
    if(items.length>1){runMealReview(lookupInputValue(),items);return}
    const item=items[0]||null;
    const ing=findIngredientForMealName(item?.name||lookupInputValue());
    const amount=parsedAmountForCandidate(ing?candidateFromIngredient(ing):null,item,false)||lookupAmount();
    if(!ing||amount<=0){showToast('Choose a saved food first');return}
    const unit=ingredientUnitLabel(ing);
    addEntryToDay(`${ing.name} (${fmt(amount)} ${unit})`,ingredientMacros(ing,amount),[{name:ing.name,amount,unit}]);
    clearFoodLookup(true);
  });
  document.getElementById('searchOnlineFood')?.addEventListener('click',runOnlineFoodSearch);
  document.getElementById('foodLookupResults')?.addEventListener('click',e=>{
    if(e.target.closest('[data-clear-food-results]')){clearFoodLookup(true);return}
    if(e.target.closest('[data-add-all-food-candidates]')){addCandidatesToDay(foodLookupCandidates);return}
    const b=e.target.closest('[data-use-food-candidate]');
    if(!b)return;
    const c=foodLookupCandidates[Number(b.dataset.useFoodCandidate)];
    if(c)addCandidateToDay(c);
  });
  document.getElementById('labelPhotoInput')?.addEventListener('change',e=>handleLabelPhoto(e.target.files?.[0]));
  setupFoodVoiceInput();
  document.getElementById('addManualEntry')?.addEventListener('click',()=>{
    const candidate=manualMacroCandidate();
    const hasMacros=Object.values(candidate.macros).some(v=>safeNum(v)>0);
    if(!lookupInputValue()){showToast('Name the food first');return}
    if(!hasMacros){showToast('Add custom macros first');return}
    addCandidateToDay(candidate);
    resetManualMacroInputs();
  });
  function entryClick(e){
    const t=e.target.closest('[data-toggle-entry]');
    if(t){const id=t.dataset.toggleEntry;if(openEntries.has(id))openEntries.delete(id);else openEntries.add(id);renderDailyTracker();renderHistory();return}
    const b=e.target.closest('[data-delete-entry]');
    if(!b)return;
    const id=b.dataset.deleteEntry,date=getSelectedDate(),entries=getEntriesForDate(date),idx=entries.findIndex(x=>x.id===id);
    if(idx<0)return;
    const removed=entries[idx];
    entries.splice(idx,1);openEntries.delete(id);saveDailyLog();renderDailyTracker();renderHistory();deleteSupabaseEntry(id);
    showUndo('Entry deleted',()=>{if(!dailyLog[date])dailyLog[date]={entries:[]};const list=dailyLog[date].entries;list.splice(Math.min(idx,list.length),0,removed);saveDailyLog();renderDailyTracker();renderHistory();if(supabaseUser)saveEntryToSupabase(date,removed,true)});
  }
  document.getElementById('dailyEntries').addEventListener('click',entryClick);
  document.getElementById('historyEntries')?.addEventListener('click',entryClick);
  document.getElementById('recentFoods')?.addEventListener('click',e=>{const b=e.target.closest('[data-recent]');if(!b)return;const item=recentItems[Number(b.dataset.recent)];if(!item)return;const m={...emptyMacros(),...(item.macros||{})};m.totalSugar=safeNum(m.addedSugar)+safeNum(m.naturalSugar);addEntryToDay(item.label,m,(item.details||[]).map(d=>({...d})))});
  document.getElementById('addBuilderIngredient').addEventListener('click',()=>{const ing=findIngredientByInput(document.getElementById('newRecipeIngredientSearch').value);if(!ing){showToast('Choose a saved ingredient');return}builderIngredients.push({ingredientId:ing.id,amount:Number(document.getElementById('newRecipeIngredientAmount').value||0)});document.getElementById('newRecipeIngredientSearch').value='';renderBuilder();showToast('Added')});
  document.getElementById('builderIngredients').addEventListener('click',e=>{const b=e.target.closest('[data-builder-remove]');if(!b)return;builderIngredients.splice(Number(b.dataset.builderRemove),1);renderBuilder()});
  document.getElementById('saveNewRecipe').addEventListener('click',()=>{const name=document.getElementById('newRecipeName').value.trim();if(!name){alert('Add a recipe name first.');return}if(!builderIngredients.length){alert('Add at least one ingredient.');return}const id=`custom-${slugify(name)}-${Date.now()}`;const tags=document.getElementById('newRecipeTags').value.split(',').map(normalizeTag).filter(Boolean);const method=document.getElementById('newRecipeMethod').value.split('\n').map(s=>s.trim()).filter(Boolean);customRecipes.push({id,name,tags,ingredients:builderIngredients,method,seasoning:[],custom:true});saveCustomRecipes();builderIngredients=[];['newRecipeName','newRecipeTags','newRecipeIngredientSearch','newRecipeMethod'].forEach(id=>document.getElementById(id).value='');document.getElementById('newRecipeIngredientAmount').value=100;refreshAllRecipes();refreshTagFilter();renderBuilder();renderRecipes();setRecipeBuilderOpen(false);showToast('Saved')});
}
async function init(){const[ingRes,recRes]=await Promise.all([fetch('ingredients.json'),fetch('recipes.json')]);ingredients=await ingRes.json();baseRecipes=await recRes.json();ingredientMap=new Map(ingredients.map(i=>[i.id,i]));await setupSupabase();if(supabaseUser){await loadSupabaseEntries();await syncUnsyncedLocalEntries()}refreshAllRecipes();document.getElementById('trackerDate').value=todayLocal();const h=document.getElementById('historyDate');if(h)h.value=todayLocal();hydrateTargetInputs();populateIngredientDatalist();refreshTagFilter();populateIngredientSelect();renderBuilder();renderRecipes();setupEvents();setupRecipeBuilderToggle();setupRecentFoodToggle();renderDailyTracker();renderHistory()}
init().catch(err=>{document.getElementById('recipeGrid').innerHTML=`<article class="card"><h2>Could not load recipes</h2><p>${esc(err.message)}</p></article>`});
